// MARK: - Networking & Security

class SecureAPIClient {
    static let shared = SecureAPIClient()
    
    private let baseURL: String
    private var authToken: String?
    private var refreshToken: String?
    private let session: URLSession
    private let encoder = JSONEncoder()
    private let decoder = JSONDecoder()
    private var cancellables = Set<AnyCancellable>()
    
    private init() {
        baseURL = "https://api.tradingplatform.com/v1"
        
        encoder.dateEncodingStrategy = .iso8601
        decoder.dateDecodingStrategy = .iso8601
        
        let config = URLSessionConfiguration.default
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        config.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "X-Platform": "iOS",
            "X-App-Version": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "1.0"
        ]
        config.timeoutIntervalForRequest = 15
        config.timeoutIntervalForResource = 30
        config.waitsForConnectivity = true
        
        let pinnedDelegate = SSLPinningDelegate()
        session = URLSession(configuration: config, delegate: pinnedDelegate, delegateQueue: nil)
    }
    
    func setAuthToken(_ token: String, refresh: String) {
        self.authToken = token
        self.refreshToken = refresh
        KeychainManager.shared.save(token, forKey: "auth_token")
        KeychainManager.shared.save(refresh, forKey: "refresh_token")
    }
    
    func loadStoredTokens() {
        authToken = KeychainManager.shared.load(forKey: "auth_token")
        refreshToken = KeychainManager.shared.load(forKey: "refresh_token")
    }
    
    func clearTokens() {
        authToken = nil
        refreshToken = nil
        KeychainManager.shared.delete(forKey: "auth_token")
        KeychainManager.shared.delete(forKey: "refresh_token")
    }
    
    private func signRequest(_ request: inout URLRequest) {
        guard let token = authToken else { return }
        request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        
        let timestamp = String(Int(Date().timeIntervalSince1970))
        request.setValue(timestamp, forHTTPHeaderField: "X-Timestamp")
        
        let nonce = UUID().uuidString
        request.setValue(nonce, forHTTPHeaderField: "X-Nonce")
        
        if let body = request.httpBody {
            let signature = generateHMAC(data: body, timestamp: timestamp, nonce: nonce)
            request.setValue(signature, forHTTPHeaderField: "X-Signature")
        }
    }
    
    private func generateHMAC(data: Data, timestamp: String, nonce: String) -> String {
        let secret = "trading_api_secret_key"
        let message = timestamp + nonce + data.base64EncodedString()
        let key = SymmetricKey(data: Data(secret.utf8))
        let signature = HMAC<SHA256>.authenticationCode(for: Data(message.utf8), using: key)
        return Data(signature).base64EncodedString()
    }
    
    enum APIError: Error, LocalizedError {
        case invalidURL
        case unauthorized
        case forbidden
        case notFound
        case rateLimited
        case serverError(Int)
        case networkError(Error)
        case decodingError(Error)
        case insufficientFunds
        case marketClosed
        case invalidOrder
        case unknown
        
        var errorDescription: String? {
            switch self {
            case .invalidURL: return "Invalid URL"
            case .unauthorized: return "Session expired. Please log in again."
            case .forbidden: return "Access denied."
            case .notFound: return "Resource not found."
            case .rateLimited: return "Too many requests. Please wait."
            case .serverError(let code): return "Server error (\(code))"
            case .networkError(let error): return error.localizedDescription
            case .decodingError: return "Data parsing error."
            case .insufficientFunds: return "Insufficient funds for this trade."
            case .marketClosed: return "Market is currently closed."
            case .invalidOrder: return "Invalid order parameters."
            case .unknown: return "An unknown error occurred."
            }
        }
    }
    
    func request<T: Decodable>(
        endpoint: String,
        method: String = "GET",
        body: Encodable? = nil,
        retryCount: Int = 2
    ) -> AnyPublisher<T, APIError> {
        guard let url = URL(string: baseURL + endpoint) else {
            return Fail(error: APIError.invalidURL).eraseToAnyPublisher()
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        
        if let body = body {
            request.httpBody = try? encoder.encode(AnyEncodable(body))
        }
        
        signRequest(&request)
        
        return session.dataTaskPublisher(for: request)
            .tryMap { [weak self] data, response -> Data in
                guard let httpResponse = response as? HTTPURLResponse else {
                    throw APIError.unknown
                }
                
                switch httpResponse.statusCode {
                case 200...299:
                    return data
                case 401:
                    throw APIError.unauthorized
                case 403:
                    throw APIError.forbidden
                case 404:
                    throw APIError.notFound
                case 429:
                    throw APIError.rateLimited
                case 422:
                    if let errorBody = try? JSONDecoder().decode(APIErrorResponse.self, from: data) {
                        if errorBody.code == "INSUFFICIENT_FUNDS" {
                            throw APIError.insufficientFunds
                        } else if errorBody.code == "MARKET_CLOSED" {
                            throw APIError.marketClosed
                        } else if errorBody.code == "INVALID_ORDER" {
                            throw APIError.invalidOrder
                        }
                    }
                    throw APIError.invalidOrder
                case 500...599:
                    throw APIError.serverError(httpResponse.statusCode)
                default:
                    throw APIError.serverError(httpResponse.statusCode)
                }
            }
            .decode(type: T.self, decoder: decoder)
            .mapError { error -> APIError in
                if let apiError = error as? APIError {
                    return apiError
                } else if error is DecodingError {
                    return .decodingError(error)
                } else {
                    return .networkError(error)
                }
            }
            .retry(retryCount)
            .receive(on: DispatchQueue.main)
            .eraseToAnyPublisher()
    }
}

struct APIErrorResponse: Decodable {
    let code: String
    let message: String
}

struct AnyEncodable: Encodable {
    private let _encode: (Encoder) throws -> Void
    
    init<T: Encodable>(_ wrapped: T) {
        _encode = wrapped.encode
    }
    
    func encode(to encoder: Encoder) throws {
        try _encode(encoder)
    }
}

// MARK: - SSL Pinning

class SSLPinningDelegate: NSObject, URLSessionDelegate {
    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        guard let serverTrust = challenge.protectionSpace.serverTrust,
              let certificate = SecTrustGetCertificateAtIndex(serverTrust, 0) else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        let serverCertificateData = SecCertificateCopyData(certificate) as Data
        
        if let localCertPath = Bundle.main.path(forResource: "trading_api_cert", ofType: "cer"),
           let localCertData = try? Data(contentsOf: URL(fileURLWithPath: localCertPath)) {
            if serverCertificateData == localCertData {
                let credential = URLCredential(trust: serverTrust)
                completionHandler(.useCredential, credential)
                return
            }
        }
        
        // Fallback: allow in debug, reject in release
        #if DEBUG
        let credential = URLCredential(trust: serverTrust)
        completionHandler(.useCredential, credential)
        #else
        completionHandler(.cancelAuthenticationChallenge, nil)
        #endif
    }
}

// MARK: - Keychain Manager

class KeychainManager {
    static let shared = KeychainManager()
    private let service = "com.tradingapp.keychain"
    
    func save(_ value: String, forKey key: String) {
        guard let data = value.data(using: .utf8) else { return }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemDelete(query as CFDictionary)
        SecItemAdd(query as CFDictionary, nil)
    }
    
    func load(forKey key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        SecItemCopyMatching(query as CFDictionary, &result)
        
        guard let data = result as? Data else { return nil }
        return String(data: data, encoding: .utf8)
    }
    
    func delete(forKey key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
}

